// Parse and validate each event
const events = $input.all().map(i => i.json);
const results = [];

for (const evt of events) {
  let payload = {};
  try {
    payload = typeof evt.payload === 'string' ? JSON.parse(evt.payload) : (evt.payload || {});
  } catch(e) {
    console.error('[exec-poller] Bad payload JSON:', evt.event_id);
    continue;
  }

  const actionType = payload.action_type || '';
  const idempKey   = payload.idempotency_key || '';

  // Skip known non-executable types (they were auto-handled)
  if (['slack_notify'].includes(actionType)) {
    results.push({ ...evt, _skip: true, _reason: 'auto_executable' });
    continue;
  }

  results.push({
    event_id:          evt.event_id,
    tenant_id:         evt.tenant_id,
    approval_id:       payload.approval_id,
    recommendation_id: payload.recommendation_id,
    action_type:       actionType,
    payload:           payload.payload || {},
    correlation_id:    payload.correlation_id,
    idempotency_key:   idempKey,
    _skip:             false
  });
}

return results.map(r => ({ json: r }));

// Validate we still haven't sent this email (idempotency)
const p = $input.first().json;
const payload = p.payload || {};

// Check quota
const maxEmails = parseInt(process.env.MAX_EMAILS_DAY || '50');
console.log(`[exec] Preparing to send email to ${payload.to_email}`);

// Basic validation
if (!payload.to_email || !payload.subject || !payload.body) {
  throw new Error(`Invalid email payload: missing to_email/subject/body`);
}

return [{ json: { ...p, _email_validated: true } }];

