UPDATE approvals SET execution_status = 'succeeded', outcome = '{"sent": true}'
WHERE id = '$(approval_id)';

UPDATE recommendations SET status = 'executed', updated_at = NOW()
WHERE id = '$(recommendation_id)';

INSERT INTO emails_sent (tenant_id, lead_id, to_email, subject, body, status, draft_id, sent_at)
VALUES ('$(tenant_id)', null, '$(payload.to_email)', '$(payload.subject)', '$(payload.body)', 'sent', '$(approval_id)', NOW())
ON CONFLICT (draft_id) DO NOTHING;

