// Handle execution failure gracefully
const p = $('Parse Events').first().json;
const err = $input.first().json;
const errMsg = err.message || err.error || 'Unknown execution error';

console.error(`[exec-poller] Execution failed for approval ${p.approval_id}: ${errMsg}`);

return [{ json: { ...p, _error: errMsg } }];
